import os, json, math, base64, traceback, subprocess, sys, uuid, threading
from flask import Flask, request, jsonify, Response
from flask_cors import CORS

app = Flask(__name__)
CORS(app)

# Track in-flight analysis threads so SIGTERM can mark them as errors
_active_jobs = {}  # job_id -> Thread

ANTHROPIC_API_KEY = os.environ.get("ANTHROPIC_API_KEY", "")
REDIS_URL         = os.environ.get("REDIS_URL", "")
MAX_PAGES_PER_CHUNK = 40
MAX_FILE_BYTES = 900 * 1024 * 1024
app.config["MAX_CONTENT_LENGTH"] = MAX_FILE_BYTES

INDEX_HTML    = base64.b64decode('').decode("utf-8")
SYSTEM_PROMPT = json.loads('"You are an expert appellate attorney and legal analyst. Analyze this court of appeals record with the thoroughness of a senior attorney preparing for oral argument. Produce a comprehensive, detailed summary.\\n\\nReturn ONLY valid JSON \\u2014 no markdown fences, no preamble, nothing else.\\n\\nThe JSON must have exactly these keys:\\n{\\n  \\"caseTitle\\": \\"Full case name and cause number if identifiable\\",\\n  \\"pleadings\\": [...],\\n  \\"witnesses\\": [...],\\n  \\"dispositiveMotions\\": [...],\\n  \\"ordersAndJudgments\\": [...],\\n  \\"trial\\": { ... },\\n  \\"pretrialMatters\\": [...],\\n  \\"trialObjections\\": [...]\\n}\\n\\nPLEADINGS \\u2014 identify every pleading filed. For each:\\n{ \\"date\\": \\"date filed\\", \\"title\\": \\"full title of the pleading\\", \\"type\\": \\"Petition|Original Answer|Amended Answer|Affirmative Defense|Third-Party Petition|Counterclaim|Cross-Claim|Intervention|Special Exceptions|other\\", \\"summary\\": \\"3-5 sentence detailed summary of the substance and allegations, including specific legal theories, parties, and relief sought\\" }\\n\\nWITNESSES \\u2014 every person who gave testimony by affidavit, declaration, deposition, or at trial. For each:\\n{ \\"name\\": \\"full name and title/role if known\\", \\"date\\": \\"date of testimony\\", \\"type\\": \\"Affidavit|Declaration|Deposition|Trial Testimony\\", \\"keyTestimony\\": [\\"detailed bullet point 1 \\u2014 specific facts, opinions, or admissions\\", \\"bullet 2\\", \\"bullet 3 \\u2014 include at least 5 bullet points per witness with specific detail\\"] }\\n\\nDISPOSITIVE MOTIONS \\u2014 every motion that could terminate the case. For each:\\n{ \\"date\\": \\"date filed\\", \\"title\\": \\"full title\\", \\"type\\": \\"Motion to Dismiss|Motion for Summary Judgment|Plea to the Jurisdiction|Motion for Directed Verdict|Motion for JNOV|Motion to Strike|other\\", \\"filedBy\\": \\"party name\\", \\"mainArguments\\": [\\"argument 1 with specifics\\", \\"argument 2\\", \\"argument 3 \\u2014 list every distinct argument made\\"], \\"courtRuling\\": \\"detailed description of ruling including legal basis stated by court\\", \\"rulingDate\\": \\"date of ruling\\" }\\n\\nORDERS AND JUDGMENTS \\u2014 every order, ruling, and judgment. For each:\\n{ \\"date\\": \\"date\\", \\"title\\": \\"full title\\", \\"type\\": \\"Interlocutory Order|Final Judgment|Partial Summary Judgment|Order on Motion|Scheduling Order|Discovery Order|Sanctions Order|other\\", \\"summary\\": \\"3-4 sentence description of what the order required, granted, or denied, and any legal findings stated\\", \\"significance\\": \\"1-2 sentences explaining why this order matters to the case outcome\\" }\\n\\nTRIAL \\u2014 if a trial occurred:\\n{ \\"occurred\\": true, \\"startDate\\": \\"date\\", \\"endDate\\": \\"date\\", \\"summary\\": \\"3-5 sentence overview of what the trial was about and how it proceeded\\", \\"days\\": [ { \\"dayNumber\\": 1, \\"date\\": \\"date\\", \\"description\\": \\"paragraph describing the day including procedural events\\", \\"witnesses\\": [\\"witness name 1\\", \\"witness name 2\\"], \\"significantEvents\\": [\\"event 1 with detail\\", \\"event 2\\", \\"event 3\\"] } ], \\"exhibits\\": [ { \\"id\\": \\"exhibit number or letter\\", \\"description\\": \\"detailed description of what the exhibit is\\", \\"offeredBy\\": \\"party\\", \\"date\\": \\"date offered\\", \\"admitted\\": true, \\"reason\\": \\"basis for admission or reason for exclusion\\" } ] }\\n\\nPRETRIAL MATTERS \\u2014 all pretrial orders, motions in limine, and pretrial rulings. For each:\\n{ \\"date\\": \\"date\\", \\"title\\": \\"full title\\", \\"type\\": \\"Motion in Limine|Pretrial Order|Scheduling Order|Pretrial Conference|Discovery Dispute|Sanctions|other\\", \\"summary\\": \\"3-4 sentences describing what was sought and the legal basis\\", \\"ruling\\": \\"detailed description of ruling\\" }\\n\\nTRIAL OBJECTIONS \\u2014 every objection made at trial. For each:\\n{ \\"date\\": \\"date\\", \\"objectingParty\\": \\"party name\\", \\"basis\\": \\"specific legal basis (hearsay, relevance, 403, foundation, etc.)\\", \\"evidenceOrTestimony\\": \\"specific description of what was being offered and by whom\\", \\"courtRuling\\": \\"how the court ruled and any explanation given\\", \\"sustained\\": true or false }\\n\\nIMPORTANT INSTRUCTIONS:\\n- Be exhaustive \\u2014 identify every document, witness, motion, and order in the record\\n- Write summaries in complete sentences with specific facts, not vague generalities\\n- Include specific dates, party names, dollar amounts, and legal standards wherever they appear\\n- For witnesses, include their specific testimony content not just topics\\n- If a section has no items, return an empty array (or for trial, occurred: false)\\n- For dates use the format found in the document"')
MERGE_PROMPT  = json.loads('"You are an expert appellate attorney. Merge all the partial summaries below into one comprehensive, deduplicated summary.\\n\\nReturn ONLY valid JSON with exactly these keys: caseTitle, pleadings, witnesses, dispositiveMotions, ordersAndJudgments, trial, pretrialMatters, trialObjections.\\n\\nRules:\\n- Deduplicate: if the same document/witness/event appears in multiple chunks, keep only one entry with the most detail\\n- Merge witness testimony: if the same witness appears in multiple chunks, combine their testimony bullet points\\n- For trial: if any chunk shows occurred: true, set occurred: true and merge all days, exhibits, and summary\\n- Keep all unique entries from all chunks\\n- Maintain the same detailed level of description from the partial summaries\\n\\nPartial summaries to merge:\\n"')
JOB_TTL = 6 * 3600  # keep results 6 hours

def _get_redis():
    if not REDIS_URL: return None
    try:
        import redis as rl
        r = rl.from_url(REDIS_URL, decode_responses=True, socket_timeout=5)
        r.ping(); return r
    except Exception as e:
        print("Redis unavailable:", e)
        return None

_redis    = _get_redis()
_mem_jobs = {}
_mem_lock = threading.Lock()

def job_set(job_id, data):
    payload = json.dumps(data)
    if _redis: _redis.setex("job:" + job_id, JOB_TTL, payload)
    else:
        with _mem_lock: _mem_jobs[job_id] = data

def job_get(job_id):
    if _redis:
        raw = _redis.get("job:" + job_id)
        if not raw: return None
        job = json.loads(raw)
        # Merge latest progress message if job is still processing
        if job.get("status") == "processing":
            prog = _redis.get("prog:" + job_id)
            if prog: job["progress"] = prog
        return job
    with _mem_lock:
        job = _mem_jobs.get(job_id)
        if job and job.get("status") == "processing":
            prog = _mem_jobs.get("prog:" + job_id)
            if prog: job = dict(job, progress=prog)
        return job


def job_progress(job_id, msg):
    """Store progress in a separate key — avoids read-modify-write races."""
    print("Progress:", msg)
    key = "prog:" + job_id
    if _redis:
        _redis.setex(key, JOB_TTL, msg)
    else:
        with _mem_lock:
            _mem_jobs[key] = msg

def make_client():
    import anthropic
    try: return anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)
    except TypeError:
        os.environ["ANTHROPIC_API_KEY"] = ANTHROPIC_API_KEY
        return anthropic.Anthropic()

def extract_pdf_documents(pdf_bytes):
    """Detect portfolio/collection; return list of (name, bytes) for each PDF."""
    import fitz
    try: doc = fitz.open(stream=pdf_bytes, filetype="pdf")
    except Exception as e: raise RuntimeError("Could not open PDF: " + str(e))
    n = doc.embfile_count()
    print("  Embedded files:", n)
    if n == 0:
        doc.close()
        return [("main.pdf", pdf_bytes)]
    extracted = []
    for i in range(n):
        try:
            info = doc.embfile_info(i)
            name = info.get("filename") or info.get("name") or ("doc_" + str(i+1) + ".pdf")
            data = doc.embfile_get(i)
            if name.lower().endswith(".pdf"):
                extracted.append((name, data))
                print("    Extracted:", name, "(" + str(len(data)//1024) + " KB)")
            else:
                print("    Skipped non-PDF:", name)
        except Exception as e:
            print("    Error on embedded file", i, ":", e)
    doc.close()
    if not extracted:
        print("  No embedded PDFs; analyzing container")
        return [("portfolio.pdf", pdf_bytes)]
    return extracted

@app.route("/")
def index(): return Response(INDEX_HTML, mimetype="text/html")

@app.route("/health")
def health():
    return jsonify({"status":"ok","html_chars":len(INDEX_HTML),
        "api_key_set":bool(ANTHROPIC_API_KEY),
        "redis":"connected" if _redis else "not configured (in-memory fallback)",
        "python":sys.version})

@app.route("/test", methods=["GET","POST"])
def test():
    info={"method":request.method,"files":list(request.files.keys()),
          "api_key_set":bool(ANTHROPIC_API_KEY),"redis":"connected" if _redis else "not configured"}
    if "file" in request.files:
        f=request.files["file"]; data=f.read()
        info.update({"file_name":f.filename,"file_bytes":len(data),"file_mb":round(len(data)/1048576,2)})
    return jsonify(info)

@app.route("/versions")
def versions():
    try:
        r=subprocess.run([sys.executable,"-m","pip","list","--format=json"],capture_output=True,text=True,timeout=15)
        pkgs=json.loads(r.stdout)
        want={p["name"].lower():p["version"] for p in pkgs if p["name"].lower() in ("anthropic","httpx","flask","pymupdf","redis")}
        return jsonify(want)
    except Exception as e: return jsonify({"error":str(e)})

@app.errorhandler(413)
def too_large(e): return jsonify({"error":"File too large."}), 413

@app.errorhandler(Exception)
def handle_exception(e):
    print("Unhandled exception:", traceback.format_exc())
    return jsonify({"error":"Server error: " + str(e)}), 500

@app.route("/upload", methods=["POST"])
def upload():
    try: return _upload()
    except Exception as e:
        print("Upload error:", traceback.format_exc())
        return jsonify({"error":"Upload failed: " + str(e)}), 500

def _upload():
    if not ANTHROPIC_API_KEY: return jsonify({"error":"Missing ANTHROPIC_API_KEY."}), 500
    if "file" not in request.files: return jsonify({"error":"No file received."}), 400
    f = request.files["file"]
    fname = f.filename or ""
    if not fname.lower().endswith(".pdf"): return jsonify({"error":"Please upload a PDF file."}), 400
    pdf_bytes = f.read()
    if not pdf_bytes: return jsonify({"error":"File is empty."}), 400
    print("Upload:", fname, " ", round(len(pdf_bytes)/1048576,1), "MB")
    job_id = str(uuid.uuid4())
    job_set(job_id, {"status":"processing","progress":"Preparing document..."})
    t = threading.Thread(target=run_analysis, args=(job_id,pdf_bytes,fname), daemon=True)
    _active_jobs[job_id] = t
    t.start()
    return jsonify({"job_id":job_id}), 202

@app.route("/status/<job_id>")
def status(job_id):
    job = job_get(job_id)
    if job is None:
        return jsonify({"status":"error","error":"Job not found — please upload again."}), 404
    return jsonify(job)

def run_analysis(job_id, pdf_bytes, fname):
    try:
        result = do_analysis(pdf_bytes, fname, job_id)
        job_set(job_id, {"status":"done","result":result})
        print("Job", job_id, "done")
    except Exception as e:
        err_msg = str(e)
        print("Job", job_id, "failed:", err_msg)
        print(traceback.format_exc())
        try:
            job_set(job_id, {"status":"error","error":err_msg})
        except Exception as redis_e:
            print("Could not write error to Redis:", redis_e)
    finally:
        _active_jobs.pop(job_id, None)  # clean up tracking dict

def do_analysis(pdf_bytes, fname, job_id=None):
    import gc
    documents = extract_pdf_documents(pdf_bytes)
    n_docs = len(documents)
    print("  Documents to analyze:", n_docs)
    del pdf_bytes; gc.collect()  # free upload bytes — no longer needed
    client = make_client()
    if n_docs == 1:
        name, doc_bytes = documents[0]
        del documents
        return analyze_single_pdf(client, doc_bytes, name, job_id)
    all_partials = []
    for doc_idx, (name, doc_bytes) in enumerate(documents):
        msg = "Document " + str(doc_idx+1) + "/" + str(n_docs) + ": " + name
        print("  Analyzing:", msg)
        if job_id: job_progress(job_id, msg)
        try:
            partials = analyze_single_pdf_to_partials(client, doc_bytes, name, job_id)
            all_partials.extend(partials)
        except Exception as e:
            print("  Error on", name, ":", e)
        finally:
            doc_bytes = None; gc.collect()  # free each doc after analysis
    del documents
    if not all_partials:
        raise RuntimeError("No readable text found in any document in this portfolio.")
    if len(all_partials) == 1: return all_partials[0]
    if job_id: job_progress(job_id, "Merging all sections into final summary...")
    return merge_results(client, all_partials)

def analyze_single_pdf(client, pdf_bytes, fname, job_id=None):
    partials = analyze_single_pdf_to_partials(client, pdf_bytes, fname, job_id)
    if not partials: raise RuntimeError("No readable text extracted from " + fname)
    return partials[0] if len(partials)==1 else merge_results(client, partials)

def analyze_single_pdf_to_partials(client, pdf_bytes, fname, job_id=None):
    import fitz, gc
    doc = fitz.open(stream=pdf_bytes, filetype="pdf")
    total_pages = len(doc)
    print("    Pages in", fname, ":", total_pages)
    if total_pages <= MAX_PAGES_PER_CHUNK and len(pdf_bytes) <= 32*1024*1024:
        if job_id: job_progress(job_id, "Analyzing " + fname + " (" + str(total_pages) + " pages)...")
        doc.close()
        result = analyze_pdf_bytes(client, pdf_bytes)
        del pdf_bytes; gc.collect()
        return [result]
    # fitz has loaded the doc — free raw bytes now
    del pdf_bytes; gc.collect()
    n = math.ceil(total_pages/MAX_PAGES_PER_CHUNK)
    print("    Chunking", fname, "into", n, "chunks")
    results = analyze_in_chunks(client, doc, total_pages, fname, job_id, n)
    doc.close(); gc.collect()
    return results

def analyze_pdf_bytes(client, pdf_bytes):
    b64 = base64.b64encode(pdf_bytes).decode("utf-8")
    r = _call_claude_with_retry(client, SYSTEM_PROMPT,
        [{"type":"document","source":{"type":"base64","media_type":"application/pdf","data":b64}},
         {"type":"text","text":"Analyze this appellate court record and return the structured JSON summary."}])
    return parse_json(r.content[0].text)

def _is_rate_limit(e):
    """Return True if the exception is a 429 / rate-limit error."""
    msg = str(e).lower()
    return ("429" in msg or "rate_limit" in msg or
            "rate limit" in msg or "overloaded" in msg or
            getattr(e, "status_code", None) == 429)

# Gunicorn is configured with --timeout 600. MAX_RETRY_SLEEP must stay
# well under that. 88s is a safe value that also fits within one rate-limit window.
MAX_RETRY_SLEEP = 88

def _retry_wait_seconds(e, attempt):
    """How long to wait before retrying after a rate-limit error.
    Reads x-ratelimit-reset-tokens from the response headers if available,
    otherwise falls back to exponential backoff. Always capped at 88s.
    """
    resp = getattr(e, "response", None) or getattr(getattr(e, "__cause__", None), "response", None)
    if resp is not None:
        headers = getattr(resp, "headers", {})
        reset_val = (headers.get("x-ratelimit-reset-tokens") or
                     headers.get("anthropic-ratelimit-tokens-reset") or
                     headers.get("retry-after"))
        if reset_val:
            import re as _re
            reset_val = str(reset_val).strip()
            m = _re.match(r"(?:(\d+)m)?(?:(\d+(?:\.\d+)?)s?)?", reset_val)
            if m:
                minutes = int(m.group(1) or 0)
                seconds = float(m.group(2) or 0)
                wait = minutes * 60 + seconds
                if wait > 0:
                    wait = min(wait + 2, MAX_RETRY_SLEEP)
                    print(f"    Rate limited. Header reset={reset_val} → waiting {wait:.0f}s...")
                    return wait
    # Fallback: 20, 40, 60, 80s (capped)
    wait = min(20 * (2 ** min(attempt, 2)), MAX_RETRY_SLEEP)
    print(f"    Rate limited (attempt {attempt+1}). Waiting {wait}s...")
    return wait

def _call_claude_with_retry(client, system, user_content, max_tokens=8000, max_retries=8):
    """Call Claude API; on rate-limit errors waits the header-specified reset
    time (or exponential backoff) before retrying.
    Also returns the tokens_used so callers can pace themselves.
    """
    import time, gc
    for attempt in range(max_retries):
        try:
            r = client.messages.create(
                model="claude-sonnet-4-20250514",
                max_tokens=max_tokens,
                system=system,
                messages=[{"role": "user", "content": user_content}]
            )
            return r
        except Exception as e:
            if _is_rate_limit(e) and attempt < max_retries - 1:
                wait = _retry_wait_seconds(e, attempt)
                # Sleep in 10s segments; each segment is well under gunicorn timeout
                slept = 0
                while slept < wait:
                    chunk_s = min(10, wait - slept)
                    time.sleep(chunk_s)
                    slept += chunk_s
                gc.collect()
                continue
            raise  # non-rate-limit error OR out of retries

def _tokens_used(r):
    """Extract input token count from a Claude response object."""
    try: return r.usage.input_tokens
    except Exception: return 20000  # safe fallback

def analyze_in_chunks(client, doc, total_pages, fname="", job_id=None, n_chunks=None):
    import time, gc
    results = []
    if n_chunks is None: n_chunks = math.ceil(total_pages/MAX_PAGES_PER_CHUNK)
    n = n_chunks
    last_input_tokens = 0   # tokens used by the previous chunk
    chunk_start_time  = 0.0 # wall-clock time the previous API call started
    RATE_LIMIT = 30000      # tokens per minute
    for i in range(n):
        start = i*MAX_PAGES_PER_CHUNK
        end   = min(start+MAX_PAGES_PER_CHUNK, total_pages)
        prefix = (fname + " ") if fname else ""
        label  = prefix + "pages " + str(start+1) + "-" + str(end) + "/" + str(total_pages)
        print("    Chunk", i+1, "/", n, ":", label)
        if job_id:
            page_from = start + 1
            page_to   = end
            doc_name  = fname if fname else "document"
            job_progress(job_id,
                "section:" + str(i+1) + "/" + str(n) +
                "|pages:" + str(page_from) + "-" + str(page_to) + "/" + str(total_pages) +
                "|doc:" + doc_name)
        # Adaptive pacing: if the previous chunk used T tokens, we need to
        # wait until T/30000 minutes have elapsed since that call started.
        if i > 0 and last_input_tokens > 0:
            elapsed = time.time() - chunk_start_time
            needed  = (last_input_tokens / RATE_LIMIT) * 60  # seconds
            wait    = max(0, needed - elapsed) + 2  # 2s buffer
            if wait > 0:
                wait = min(wait, MAX_RETRY_SLEEP)
                print(f"    Pacing: {last_input_tokens} tokens used, waiting {wait:.1f}s before next chunk...")
                # Sleep in segments to stay under gunicorn timeout
                slept = 0
                while slept < wait:
                    time.sleep(min(10, wait - slept))
                    slept += 10
        parts = []
        for p in range(start, end):
            t = doc[p].get_text("text")
            if t.strip(): parts.append("[Page " + str(p+1) + "]" + chr(10) + t)
        text = (chr(10)+chr(10)).join(parts)
        parts = None  # free page text list
        if not text.strip(): continue
        prompt = "Analyze this section (" + label + ") and return the structured JSON summary." + chr(10)*2 + text
        text = None  # free extracted text before API call
        gc.collect()
        chunk_start_time = time.time()
        r = _call_claude_with_retry(client, SYSTEM_PROMPT, prompt)
        last_input_tokens = _tokens_used(r)
        prompt = None
        results.append(parse_json(r.content[0].text))
        print(f"    Chunk {i+1}/{n} OK — pages {start+1}-{end}/{total_pages} ({last_input_tokens} tokens)")
        gc.collect()
    return results

def merge_results(client, partials):
    import gc
    BATCH = 8  # merge 8 partials at a time to keep payloads manageable
    print("Merging", len(partials), "partials in batches of", BATCH)
    while len(partials) > 1:
        next_round = []
        for i in range(0, len(partials), BATCH):
            batch = partials[i:i+BATCH]
            if len(batch) == 1:
                next_round.append(batch[0])
                continue
            combined = json.dumps(batch, indent=2)
            batch = None; gc.collect()
            print("  Merge batch", (i//BATCH)+1, "of", math.ceil(len(partials)/BATCH))
            r = _call_claude_with_retry(client, MERGE_PROMPT+combined, "Merge these into one comprehensive JSON summary.")
            combined = None; gc.collect()
            next_round.append(parse_json(r.content[0].text))
        partials = next_round
    return partials[0]

def parse_json(raw):
    clean = raw.strip()
    if "```" in clean:
        for part in clean.split("```"):
            part = part.strip()
            if part.startswith("json"): part = part[4:].strip()
            try: return json.loads(part)
            except Exception: continue
    return json.loads(clean)

# ── SIGTERM handler ────────────────────────────────────────────────────────
# Render sends SIGTERM before shutting down the process. We catch it and
# write an error to Redis for every in-flight job so the browser shows a
# real error message instead of spinning forever.
import signal
def _handle_sigterm(signum, frame):
    print("SIGTERM received — marking", len(_active_jobs), "active jobs as failed")
    for jid in list(_active_jobs.keys()):
        try:
            job_set(jid, {"status":"error",
                "error":"The server was restarted while your document was being analyzed. "
                        "Please upload your document again."})
            print("  Marked job", jid, "as error")
        except Exception as e:
            print("  Could not mark job", jid, ":", e)
    # Allow gunicorn to proceed with its shutdown
    raise SystemExit(0)

signal.signal(signal.SIGTERM, _handle_sigterm)

if __name__ == "__main__":
    port = int(os.environ.get("PORT", 5000))
    app.run(host="0.0.0.0", port=port, debug=False)
